ALGORITHM CUDA_Trapezoidal_Rule
INPUT: a, b (integration bounds), n (number of subintervals), h (step size), result_p (device pointer)
OUTPUT: Approximate integral of f(x) from a to b

BEGIN
 // Each thread computes f(x_i) for one point
 my_i = blockIdx.x * blockDim.x + threadIdx.x

 // Guard: ensure thread index is within valid range [0, n]
 IF my_i <= n THEN
 // Calculate x coordinate for this thread
 my_x = a + my_i * h

 // Evaluate the function at this point
 my_f = f(my_x)

 // Apply half-weight to boundary points (i=0 and i=n)
 IF my_i == 0 OR my_i == n THEN
 my_f = my_f * 0.5
 END IF

 // Atomically add to global result (thread-safe accumulation)
 atomicAdd(result_p, my_f)
 END IF
END

ALGORITHM Host_Integration
INPUT: a, b, n
OUTPUT: Final integral value

BEGIN
 h = (b - a) / n

 // Allocate device memory for result
 d_result = cudaMalloc(sizeof(float))

 // Initialize result to zero (CRITICAL)
 cudaMemset(d_result, 0, sizeof(float))

 // Configure kernel launch parameters
 threadsPerBlock = 256
 numBlocks = ceil((n + 1) / threadsPerBlock)

 // Launch kernel
 CUDA_Trapezoidal_Rule <<<numBlocks, threadsPerBlock>>>(a, b, n, h, d_result)

 // Copy result from device to host
 h_result = cudaMemcpy(d_result, sizeof(float), DeviceToHost)

 // Multiply by h to get final integral
 integral = h * h_result

 // Free device memory
 cudaFree(d_result)

 RETURN integral
END

/*
 * CUDA Trapezoidal Rule I: Basic atomicAdd Approach
 * Integrates f(x) = x^2 from 0 to 1 using n subintervals
 * 
 * Compile: nvcc trapezoidal_atomic.cu -o trapezoidal
 * Run: ./trapezoidal
 */

#include <stdio.h>
#include <cuda_runtime.h>

#define CUDA_CHECK(call) \
 do { \
 cudaError_t err = call; \
 if (err != cudaSuccess) { \
 fprintf(stderr, "CUDA error at %s:%d: %s\n", \
 __FILE__, __LINE__, cudaGetErrorString(err)); \
 exit(EXIT_FAILURE); \
 } \
 } while(0)

/* Device function: the integrand f(x) = x^2 */
__device__ float f(float x) {
 return x * x;
}

/* CUDA Kernel: Multi-block trapezoidal rule with atomicAdd */
__global__ void dev_trap(float a, float b, int n, float h, float* result_p) {
 // Calculate global thread index: unique ID across all blocks
 int my_i = blockIdx.x * blockDim.x + threadIdx.x;

 // Guard condition: only valid indices [0, n] should contribute
 if (my_i <= n) {
 // Compute x coordinate for this thread's subinterval point
 float my_x = a + my_i * h;

 // Evaluate the function at this point
 float my_f = f(my_x);

 // Apply half-weight to boundary terms (f(a) and f(b))
 if (my_i == 0 || my_i == n) {
 my_f *= 0.5f;
 }

 // Atomically add to global result (thread-safe accumulation)
 atomicAdd(result_p, my_f);
 }
}

int main() {
 // Integration parameters
 float a = 0.0f; // Lower bound
 float b = 1.0f; // Upper bound
 int n = 1024 * 1024; // Number of subintervals (1 million)
 float h = (b - a) / n; // Step size

 printf("CUDA Trapezoidal Rule (atomicAdd approach)\n");
 printf("Integrating f(x) = x^2 from %.1f to %.1f\n", a, b);
 printf("Using n = %d subintervals, h = %.10f\n\n", n, h);

 // Allocate device memory for result (single float for accumulation)
 float* d_result;
 CUDA_CHECK(cudaMalloc(&d_result, sizeof(float)));

 // Initialize result to zero - CRITICAL for correct accumulation
 CUDA_CHECK(cudaMemset(d_result, 0, sizeof(float)));

 // Configure kernel launch
 int threadsPerBlock = 256;
 // Calculate number of blocks to cover all n+1 points (0 through n)
 int numBlocks = (n + 1 + threadsPerBlock - 1) / threadsPerBlock;

 printf("Launching kernel with %d blocks x %d threads = %d total threads\n",
 numBlocks, threadsPerBlock, numBlocks * threadsPerBlock);

 // Launch the kernel
 dev_trap<<<numBlocks, threadsPerBlock>>>(a, b, n, h, d_result);

 // Check for kernel launch errors
 CUDA_CHECK(cudaGetLastError());

 // Wait for kernel to complete
 CUDA_CHECK(cudaDeviceSynchronize());

 // Copy result from device to host
 float h_result;
 CUDA_CHECK(cudaMemcpy(&h_result, d_result, sizeof(float), cudaMemcpyDeviceToHost));

 // Final integral = h * (sum of weighted f(x_i) values)
 float integral = h * h_result;

 // Compute exact answer and error
 float exact = 1.0f / 3.0f; // Integral of x^2 from 0 to 1
 float error = fabsf(integral - exact);

 printf("\nResults:\n");
 printf(" Computed integral: %.15f\n", integral);
 printf(" Exact integral: %.15f\n", exact);
 printf(" Absolute error: %.15e\n", error);

 // Cleanup
 CUDA_CHECK(cudaFree(d_result));
 CUDA_CHECK(cudaDeviceReset());

 return 0;
}

/*
 * KEY OBSERVATIONS:
 * 
 * 1. THREAD MAPPING: Each thread handles one evaluation point x_i
 * - Global index = blockIdx.x * blockDim.x + threadIdx.x
 * - x_i = a + i * h
 * 
 * 2. BOUNDARY HANDLING: f(a) and f(b) get half weight
 * - if (my_i == 0 || my_i == n) my_f *= 0.5
 * 
 * 3. ATOMICADD: Serializes all writes to result_p
 * - Ensures correct accumulation but limits parallelism
 * - O(n) total time instead of O(n/p)
 * 
 * 4. MEMORY INITIALIZATION: cudaMemset to 0 is essential
 * - Without it, accumulation starts from garbage
 * 
 * 5. FLOATING-POINT NON-DETERMINISM:
 * - atomicAdd order varies between runs
 * - Floating-point addition is not associative
 * - Results may differ slightly in last significant bits
 */

/*
 * CUDA Trapezoidal Rule: Single Block Version
 * 
 * This version demonstrates the basic concept using only threadIdx.x
 * Limited to n <= 1024 (max threads per block on most GPUs)
 * 
 * Useful for understanding before moving to multi-block version.
 */

#include <stdio.h>
#include <cuda_runtime.h>

#define CUDA_CHECK(call) \
 do { \
 cudaError_t err = call; \
 if (err != cudaSuccess) { \
 fprintf(stderr, "CUDA error at %s:%d: %s\n", \
 __FILE__, __LINE__, cudaGetErrorString(err)); \
 exit(EXIT_FAILURE); \
 } \
 } while(0)

/* Device function: example integrand f(x) = sin(x) */
__device__ float f(float x) {
 return sinf(x); // Using sinf for single precision
}

/* Single-block kernel: uses only threadIdx.x */
__global__ void dev_trap_single_block(float a, float b, int n, float h, float* result_p) {
 // Simple index using only thread ID within block
 int my_i = threadIdx.x;

 // Guard: ensure thread index is valid
 if (my_i <= n) {
 // Calculate x coordinate
 float my_x = a + my_i * h;

 // Evaluate function
 float my_f = f(my_x);

 // Half-weight for boundaries
 if (my_i == 0 || my_i == n) {
 my_f *= 0.5f;
 }

 // Atomic add to accumulate
 atomicAdd(result_p, my_f);
 }
}

/* Multi-block kernel: uses full indexing formula */
__global__ void dev_trap_multi_block(float a, float b, int n, float h, float* result_p) {
 // Global thread index across all blocks
 int my_i = blockIdx.x * blockDim.x + threadIdx.x;

 if (my_i <= n) {
 float my_x = a + my_i * h;
 float my_f = f(my_x);

 if (my_i == 0 || my_i == n) {
 my_f *= 0.5f;
 }

 atomicAdd(result_p, my_f);
 }
}

void run_single_block_demo() {
 printf("=== Single Block Demo ===\n");

 float a = 0.0f, b = 3.14159265f; // Integrate sin(x) from 0 to pi
 int n = 512; // Small n for single block
 float h = (b - a) / n;

 float* d_result;
 CUDA_CHECK(cudaMalloc(&d_result, sizeof(float)));
 CUDA_CHECK(cudaMemset(d_result, 0, sizeof(float)));

 // Single block with n+1 threads (enough for all points)
 int threads = n + 1;
 printf("Using %d threads in single block\n", threads);

 dev_trap_single_block<<<1, threads>>>(a, b, n, h, d_result);
 CUDA_CHECK(cudaGetLastError());
 CUDA_CHECK(cudaDeviceSynchronize());

 float h_result;
 CUDA_CHECK(cudaMemcpy(&h_result, d_result, sizeof(float), cudaMemcpyDeviceToHost));

 float integral = h * h_result;
 float exact = 2.0f; // Integral of sin(x) from 0 to pi is 2

 printf("Computed: %.10f, Exact: %.10f, Error: %.10e\n\n", integral, exact, fabsf(integral - exact));

 CUDA_CHECK(cudaFree(d_result));
}

void run_multi_block_demo() {
 printf("=== Multi Block Demo ===\n");

 float a = 0.0f, b = 3.14159265f;
 int n = 1024 * 1024; // 1 million subintervals
 float h = (b - a) / n;

 float* d_result;
 CUDA_CHECK(cudaMalloc(&d_result, sizeof(float)));
 CUDA_CHECK(cudaMemset(d_result, 0, sizeof(float)));

 int threadsPerBlock = 256;
 int numBlocks = (n + 1 + threadsPerBlock - 1) / threadsPerBlock;

 printf("Using %d blocks x %d threads = %d total threads\n",
 numBlocks, threadsPerBlock, numBlocks * threadsPerBlock);

 dev_trap_multi_block<<<numBlocks, threadsPerBlock>>>(a, b, n, h, d_result);
 CUDA_CHECK(cudaGetLastError());
 CUDA_CHECK(cudaDeviceSynchronize());

 float h_result;
 CUDA_CHECK(cudaMemcpy(&h_result, d_result, sizeof(float), cudaMemcpyDeviceToHost));

 float integral = h * h_result;
 float exact = 2.0f;

 printf("Computed: %.10f, Exact: %.10f, Error: %.10e\n\n", integral, exact, fabsf(integral - exact));

 CUDA_CHECK(cudaFree(d_result));
}

int main() {
 printf("CUDA Trapezoidal Rule: Single vs Multi-Block\n\n");

 run_single_block_demo();
 run_multi_block_demo();

 printf("Key Difference:\n");
 printf(" Single block: my_i = threadIdx.x\n");
 printf(" Multi block: my_i = blockIdx.x * blockDim.x + threadIdx.x\n");

 CUDA_CHECK(cudaDeviceReset());
 return 0;
}

/*
 * COMPARISON:
 * 
 * Single Block Version:
 * - Simpler: uses only threadIdx.x
 * - Limited: max ~1024 threads (n <= 1024)
 * - Good for learning and small problems
 * 
 * Multi-Block Version:
 * - Uses: blockIdx.x * blockDim.x + threadIdx.x 
 * - Scales: can handle millions of subintervals
 * - Production use for large n
 * 
 * Both versions use atomicAdd, so both suffer from
 * the serialization bottleneck described in the topic.
 */
